#include <cstdint>\n#include <iostream>\n#include <vector>\n#include <algorithm>\n\nclass Graph {\n public:\n  Graph(size_t n, const std::vector<std::pair<size_t, size_t>>& edges) {\n    table_.resize(n);  // 0 1 2 3...\n    reversed_table_.resize(n);\n    tin_.resize(n, 0);\n    tout_.resize(n, 0);\n    visited_.resize(n, false);\n    Build(edges);\n  }\n\n  std::vector<size_t> StartKosaraju() {\n    auto n = table_.size();\n    for (size_t i = 0; i < n; i++) {\n      if (GetColor(i) == Colors_::White) {\n        Dfs(i);\n      }\n    }\n\n    vertexes_.resize(tout_.size());\n    for (size_t i = 0; i < vertexes_.size(); i++) {\n      vertexes_[i] = i;\n    }\n\n    // сортировка вершин\n    sorted_tout_ = tout_;\n    HeapSort();\n    comps_.resize(n);\n    for (auto i : vertexes_) {\n      if (!visited_[i]) {\n        SecondDfs(i);\n        k_++;\n      }\n    }\n    return comps_;\n  }\n\n private:\n  void Dfs(size_t start) {\n    tin_[start] = time_++;\n    const std::vector<size_t>& children = table_[start];\n    for (auto i : children) {\n      switch (GetColor(i)) {\n        case Colors_::White:\n          Dfs(i);\n        case Colors_::Gray:\n        case Colors_::Black:\n          break;\n      }\n    }\n    tout_[start] = time_++;\n  }\n\n  void SecondDfs(size_t start) {\n    visited_[start] = true;\n    comps_[start] = k_;\n    for (auto i : reversed_table_[start]) {\n      if (!visited_[i]) {\n        SecondDfs(i);\n      }\n    }\n  }\n\n  void Build(const std::vector<std::pair<size_t, size_t>>& edges) {\n    for (const std::pair<size_t, size_t>& pair : edges) {\n      auto first = pair.first - 1;\n      auto second = pair.second - 1;\n      table_[first].push_back(second);\n      reversed_table_[second].push_back(first);\n    }\n  }\n\n  void HeapSort() {\n    auto size = vertexes_.size();\n    for (size_t i = size / 2 - 1; i >= 1; i--) {\n      SiftDown(i, size);\n    }\n    SiftDown(0, size);\n    for (size_t i = size - 1; i >= 1; i--) {\n      std::swap(sorted_tout_[0], sorted_tout_[i]);\n      std::swap(vertexes_[0], vertexes_[i]);\n      SiftDown(0, i);\n    }\n  }\n\n  void SiftDown(size_t index, size_t size) {\n    size_t left = index * 2 + 1;\n    size_t right = left + 1;\n    size_t min_index = index;\n    if (left < size && sorted_tout_[left] < sorted_tout_[min_index]) {\n      min_index = left;\n    }\n    if (right < size && sorted_tout_[right] < sorted_tout_[min_index]) {\n      min_index = right;\n    }\n    if (index == min_index) {\n      return;\n    }\n    std::swap(vertexes_[index], vertexes_[min_index]);\n    std::swap(sorted_tout_[index], sorted_tout_[min_index]);\n    SiftDown(min_index, size);\n  }\n\n  enum class Colors_;\n  Colors_ GetColor(size_t start) {\n    if (tin_[start] == 0) {\n      return Colors_::White;\n    }\n    if (tout_[start] == 0) {\n      return Colors_::Gray;\n    }\n    return Colors_::Black;\n  }\n\n  // bool is_top_sortable_ = true;\n  size_t time_ = 1;\n  size_t k_ = 1;\n  std::vector<std::vector<size_t>> table_;\n  std::vector<std::vector<size_t>> reversed_table_;\n  std::vector<size_t> tin_;\n  std::vector<size_t> tout_;\n  std::vector<size_t> sorted_tout_;\n  std::vector<size_t> vertexes_;\n  std::vector<size_t> comps_;\n  std::vector<bool> visited_;\n  enum class Colors_ { White, Gray, Black };\n};\n\nint main() {\n  size_t n = 0;\n  size_t m = 0;\n  std::cin >> n >> m;\n  std::vector<std::pair<size_t, size_t>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    size_t i = 0;\n    size_t j = 0;\n    std::cin >> i >> j;\n    edges[it] = {i, j};\n  }\n\n  Graph graph(n, edges);\n  auto comps = graph.StartKosaraju();\n  std::cout << *std::max_element(comps.begin(), comps.end()) << std::endl;\n  for (auto i : comps) {\n    std::cout << i << ' ';\n  }\n  std::cout << std::endl;\n  return 0;\n}